import subprocess
def execute_tool(command: str, timeout: int = 30):
    try:
        r = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=timeout, encoding='utf-8', errors='replace')
        return r.stdout if r.returncode == 0 else f"错误: {r.stderr}\n返回码: {r.returncode}"
    except subprocess.TimeoutExpired:
        return "错误: 命令超时"
    except Exception as e:
        return f"错误: {str(e)}"

